sub handle_registration {
    my ($q) = @_;

    my $username = $q->param('reg_username');
    my $password = $q->param('reg_password');
    my $confirm_password = $q->param('reg_confirm_password');

    unless ($username && $password && $confirm_password) {
        print p(b('Error: All fields are required for registration.'));
        show_forms();
        return;
    }

    unless ($password eq $confirm_password) {
        print p(b('Error: Passwords do not match.'));
        show_forms();
        return;
    }

    my %users = read_users_file();

    if (exists $users{$username}) {
        print p(b("Error: Username '$username' already exists."));
        show_forms();
        return;
    }

    my $hashed_password = md5_hex($password);

    if (write_user_to_file($username, $hashed_password)) {
        print p(b("Registration successful for user '$username'. You can now login."));
    } else {
        print p(b("Error: Could not register user '$username'. Please try again later."));
    }
    show_forms();
}

sub handle_login {
    my ($q) = @_;

    my $username = $q->param('login_username');
    my $password = $q->param('login_password');

    unless ($username && $password) {
        print p(b('Error: Both username and password are required for login.'));
        show_forms();
        return;
    }

    my %users = read_users_file();

    unless (exists $users{$username}) {
        print p(b('Error: Invalid username or password.'));
        show_forms();
        return;
    }

    my $stored_hash = $users{$username};
    my $input_hash = md5_hex($password);

    if ($input_hash eq $stored_hash) {
        print p(b("Login successful for user '$username'."));
        # In a full application, you would set a session or cookie here.
    } else {
        print p(b('Error: Invalid username or password.'));
    }
    show_forms();
}

sub read_users_file {
    my %users;
    # Attempt to create the file if it doesn't exist
    open my $fh, '>>', $users_file or do {
        warn "Could not open or create users file '$users_file': $!";
        return %users;
    };
    close $fh; # Close after creating

    open $fh, '<', $users_file or do {
        warn "Could not open users file '$users_file' for reading: $!";
        return %users;
    };
    flock $fh, LOCK_SH; # Shared lock for reading
    while (my $line = <$fh>) {
        chomp $line;
        next unless $line;
        if ($line =~ /^([^:]+):(.+)$/) {
            $users{$1} = $2;
        }
    }
    close $fh;
    return %users;
}

sub write_user_to_file {
    my ($username, $hashed_password) = @_;

    open my $fh, '>>', $users_file or do {
        warn "Could not open users file '$users_file' for writing: $!";
        return 0;
    };
    flock $fh, LOCK_EX; # Exclusive lock for writing
    print $fh "$username:$hashed_password\n";
    close $fh;
    return 1;
}